import json
import os

# Helper function to load data
def load_data(key):
    result = locals()[key]
    if isinstance(result, str) and result.endswith('.json'):
        with open(result, 'r') as f:
            return json.load(f)
    return result

# Load all available analysis results
results = []

# Batch 1 (from var_functions.query_db:36)
try:
    batch1 = load_data('var_functions.query_db:36')
    if batch1:
        results.extend(batch1)
except:
    pass

# Batch 2 (from var_functions.query_db:38)
try:
    batch2 = load_data('var_functions.query_db:38')
    if batch2:
        results.extend(batch2)
except:
    pass

# Batch 3 (from var_functions.query_db:64)
try:
    batch3 = load_data('var_functions.query_db:64')
    if batch3:
        results.extend(batch3)
except:
    pass

# Load NYSE stock data to get company names
stockinfo_path = locals()['var_functions.query_db:0']
if isinstance(stockinfo_path, str) and stockinfo_path.endswith('.json'):
    with open(stockinfo_path, 'r') as f:
        stockinfo_data = json.load(f)
else:
    stockinfo_data = stockinfo_path

company_names = {item['Symbol']: item['Company Description'] for item in stockinfo_data}

# Process results - find stocks with more up days than down days
stocks_with_more_up_days = []
for result in results:
    up_days = float(result.get('up_days', 0))
    down_days = float(result.get('down_days', 0))
    symbol = result['Symbol']

    if up_days > down_days:
        stocks_with_more_up_days.append({
            'symbol': symbol,
            'company_name': company_names.get(symbol, 'Unknown'),
            'up_days': up_days,
            'down_days': down_days,
            'difference': up_days - down_days
        })

# Sort by difference (largest positive difference first)
stocks_with_more_up_days.sort(key=lambda x: x['difference'], reverse=True)

# Count analyzed symbols
analyzed_symbols = {result['Symbol'] for result in results}

print('__RESULT__:')
print(json.dumps({
    'total_results_loaded': len(results),
    'total_analyzed_symbols': len(analyzed_symbols),
    'stocks_with_more_up_days': len(stocks_with_more_up_days),
    'top_10_stocks': stocks_with_more_up_days[:10],
    'all_nyse_symbols': len(company_names)
}))

